import React from 'react'

const Dashboard = React.lazy(() => import('./views/dashboard/Dashboard'))
const Logout = React.lazy(()=> import('./views/Register/Logout'));
const BusinessList = React.lazy(() => import('./views/Business/list/businessList'))
const BusinessDetails = React.lazy(() => import('./views/Business/businessDetails'))
const TestimonialList = React.lazy(() => import('./views/Testimonial/list/testimonialList'))
const TestimonialCreate = React.lazy(() => import('./views/Testimonial/create/addTestimonial'))
const BlogCreate = React.lazy(() => import('./views/Blog/create/blogCreate'))
const BlogEdit = React.lazy(() => import('./views/Blog/Edit/blogEdit'))
const BlogList = React.lazy(() => import('./views/Blog/list/blogList'))
const Editor = React.lazy(() => import('./views/pages/editor/Editor'))
const BlogPageEditor = React.lazy(() => import('./views/Blog/create/blogCreateEditor'))
const TeamCreate = React.lazy(() => import('./views/Team/Create/AddTeamMember'))
const TeamList = React.lazy(() => import('./views/Team/TeamList'))
const TeamEdit = React.lazy(() => import('./views/Team/Edit/EditTeamMember'))
const PositionList = React.lazy(() => import('./views/Positions/PositionList'))
const PositionCreate = React.lazy(() => import('./views/Positions/Create/CreatePosition'))
const PositionEdit = React.lazy(() => import('./views/Positions/Edit/EditPosition'))
const PersonaList = React.lazy(() => import('./views/persona/PersonaList'))
const PersonaCreate = React.lazy(() => import('./views/persona/create/createPersona'))
const PersonaEdit = React.lazy(() => import('./views/persona/edit/editPersona'))
const InterestList = React.lazy(() => import('./views/interest/InterestList'))
const InterestCreate = React.lazy(() => import('./views/interest/create/createInterest'))
const InterestEdit = React.lazy(() => import('./views/interest/edit/editInterest'))
const CategoryList = React.lazy(() => import('./views/Category/CategoryList'))
const CategoryCreate = React.lazy(() => import('./views/Category/Create/CreateCategory'))
const CategoryEdit = React.lazy(() => import('./views/Category/Edit/EditCategory'))
const TriviaList = React.lazy(() => import('./views/Trivia/TriviaList'))
const TriviaCreate = React.lazy(() => import('./views/Trivia/Create/CreateTrivia'))
const TriviaEdit = React.lazy(() => import('./views/Trivia/Edit/EditTrivia'))
const InfrograpicList = React.lazy(() => import('./views/Infrograpic/InfrograpicList'))
const InfrograpicCreate = React.lazy(() => import('./views/Infrograpic/Create/CreateInfrograpic'))
const InfrograpicEdit = React.lazy(() => import('./views/Infrograpic/Edit/EditInfrograpic'))
const CareerDepartmentList = React.lazy(() => import('./views/Career/Department/List/listDepartment'));
const CareerDepartmentCreate = React.lazy(() => import('./views/Career/Department/Create/createDepartment'));
const CareerDepartmentEdit = React.lazy(() => import('./views/Career/Department/Edit/editDepartment'));
const CareerApplicantList = React.lazy(() => import('./views/Career/Applicant/ApplicantList'));
const CareerApplicantDetails = React.lazy(() => import('./views/Career/Applicant/ApplicantDetails'));
const UserList = React.lazy(()=> import('./views/Register/List/UserList'));
const CreateUser = React.lazy(()=> import('./views/Register/Create/createUser'));
const UserEdit = React.lazy(()=>import('./views/Register/Update/updateUser'))
const RoleList = React.lazy(()=> import('./views/Register/Role/RoleList'));
const CreateUserRole = React.lazy(()=> import('./views/Register/Role/CreateRole/CreateRole'));
const EditUserRole = React.lazy(()=> import('./views/Register/Role/EditRole/EditRole'));
const RemarksList = React.lazy(()=> import('./views/Business/Remarks/RemarksList'));
const CreateRemarks = React.lazy(()=> import('./views/Business/Remarks/Create/CreateRemarks'));
const EditRemarks = React.lazy(()=> import('./views/Business/Remarks/Edit/EditRemarks'));
const JobPositionCreate = React.lazy(() => import('./views/Career/JobPosition/Create/CreateJobPosition'));
const JobPositionEdit = React.lazy(() => import('./views/Career/JobPosition/Edit/EditJobPosition'))
const JobPositionList = React.lazy(() => import('./views/Career/JobPosition/JobPositionList'));
const JobDescriptionCreate = React.lazy(() => import('./views/Career/JobDescription/Create/CreateJobDescription'));
const JobDescriptionEdit = React.lazy(() => import('./views/Career/JobDescription/Edit/EditJobDescription'))
const JobDescriptionList = React.lazy(() => import('./views/Career/JobDescription/JobDescriptionList'));
const JobDescriptionPositionList = React.lazy(() => import('./views/Career/JobDescriptionPosition/JobDescriptionPositionList'));
const SignUpCodeList = React.lazy(() => import('./views/SignUpCode/SignUpCodeList'));
const CreateSignUpCode = React.lazy(() => import('./views/SignUpCode/Create/CreateSignUpCode'));
const CreatePaymentLink = React.lazy(() => import('./views/SubscriptionSummary/GeneratePaymentLink/Create/CreatePaymentLink'));
const SummaryList = React.lazy(() => import('./views/SubscriptionSummary/GeneratePaymentLink/SummaryList'));
const PaymentRecievedList = React.lazy(() => import('./views/SubscriptionSummary/PaymentRecieved/PaymentRecievedList'));
const PaymentRefundedList = React.lazy(() => import('./views/SubscriptionSummary/PaymentRefunded/PaymentRefundedList'));
const TransactionList = React.lazy(() => import('./views/SubscriptionSummary/Transaction/TransactionList'));
const UserViewQueryList = React.lazy(() => import('./views/UserViewQuery/UserViewQueryList'));
const ProductList = React.lazy(() => import('./views/Product/ProductList'));
const CreateProduct = React.lazy(() => import('./views/Product/Create'));
const UpdateProduct = React.lazy(() => import('./views/Product/Update'));
const SubcriptionPlanList = React.lazy(() => import('./views/SubscriptionPlan/SubscriptionPlanList'));
const SubscriptionPlanCreate =  React.lazy(() => import('./views/SubscriptionPlan/Create'));
const SubcriptionPlanUpdate =  React.lazy(() => import('./views/SubscriptionPlan/Update'));
const UserDetails = React.lazy(() => import('./views/UserDetails'));
const UserViewQueryDetails =  React.lazy(() => import('./views/UserViewQuery/UserViewQueryDetails'));

const routes = [
  { path: '/', exact: true, name: 'Home' },
  { path: '/dashboard', name: 'Dashboard', element: Dashboard },
  { path: '/business', name: 'Business List', element: BusinessList },
  { path: '/user-view-query', name: 'User View Query List', element: UserViewQueryList },
  { path: '/business/details/:id', name: 'Business Details', element: BusinessDetails },
  { path: '/user-view-query/details/:id', name: 'Business Details', element: UserViewQueryDetails },
  { path: '/testimonial', name: 'Testimonial List', element: TestimonialList },
  { path: '/testimonial/create', name: 'Testimonial Create', element: TestimonialCreate },
  { path: '/blog/create', name: 'Blog Create', element: BlogCreate },
  { path: '/blog/page/:pageId', name: 'Blog Update', element: BlogPageEditor },
  { path: '/blog', name: 'Blog List', element: BlogList },
  { path: '/blog/edit/:id', name: 'Blog Edit', element: BlogEdit },
  { path: '/team/create', name: 'Team Create', element: TeamCreate },
  { path: '/team', name: 'Team List', element: TeamList },
  { path: '/team/edit/:id', name: 'Team Update', element: TeamEdit },
  { path: '/position', name: 'Position List', element: PositionList },
  { path: '/position/create', name: 'Position Create', element: PositionCreate },
  { path: '/position/edit/:id', name: 'Position Update', element: PositionEdit },
  { path: '/persona', name: 'Persona List', element: PersonaList },
  { path: '/persona/create', name: 'Persona Create', element: PersonaCreate },
  { path: '/persona/edit/:id', name: 'Persona Update', element: PersonaEdit },
  { path: '/interest', name: 'Interest List', element: InterestList },
  { path: '/interest/create', name: 'Interest Create', element: InterestCreate },
  { path: '/interest/edit/:id', name: 'Interest Update', element: InterestEdit },
  { path: '/category', name: 'Category List', element: CategoryList },
  { path: '/category/create', name: 'Category Create', element: CategoryCreate },
  { path: '/category/edit/:id', name: 'Category Update', element: CategoryEdit },
  { path: '/trivia', name: 'Trivia List', element: TriviaList },
  { path: '/trivia/create', name: 'Trivia Create', element: TriviaCreate },
  { path: '/trivia/edit/:id', name: 'Trivia Update', element: TriviaEdit },
  { path: '/infrograpic', name: 'Infographic List', element: InfrograpicList },
  { path: '/infrograpic/create', name: 'Infographic Create', element: InfrograpicCreate },
  { path: '/infrograpic/edit/:id', name: 'Infographic Update', element: InfrograpicEdit },
  { path: '/career/department', name: 'Department List', element: CareerDepartmentList },
  { path: '/career/department/create', name: 'Department Create', element: CareerDepartmentCreate },
  { path: '/career/department/edit/:id', name: 'Department Edit', element: CareerDepartmentEdit },
  { path: '/career/position', name: 'Position List', element: JobPositionList },
  { path: '/career/position/create', name: 'Position Create', element: JobPositionCreate },
  { path: '/career/position/edit/:id', name: 'Position Edit', element: JobPositionEdit },
  { path: '/career/job-description', name: 'Job Description List', element: JobDescriptionList },
  { path: '/career/job-description/create', name: 'Job Description Create', element: JobDescriptionCreate },
  { path: '/career/job-description/edit/:id', name: 'Job Description Edit', element: JobDescriptionEdit },
  { path: '/career/job-description-position/:id', name: 'Job Description Position List', element: JobDescriptionPositionList },
  { path: '/career/applicant', name: 'Applicant List', element: CareerApplicantList },
  { path: '/career/applicant/:id', name: "Applicant Details", element: CareerApplicantDetails},
  { path: '/user', name: 'User List', element: UserList},
  { path: '/user/create', name: 'Create User', element: CreateUser},
  { path: '/user/edit/:id', name: 'Edit User', element: UserEdit},
  { path: '/role', name: 'User Role List', element: RoleList},
  { path: '/role/create', name: 'Create', element: CreateUserRole},
  { path: '/role/edit/:id', name: 'Edit', element: EditUserRole},
  { path: '/business/remarks', name: 'Business Remarks List', element: RemarksList },
  { path: '/user-view-query/remarks', name: 'User View Query Remarks List', element: RemarksList },
  { path: '/business/remarks/create', name: 'Business Remarks Create', element: CreateRemarks },
  { path: '/business/remarks/edit/:id', name: 'Business Remarks Edit', element: EditRemarks },
  { path: '/user-view-query/remarks/create', name: 'User View Query Remarks Create', element: CreateRemarks },
  { path: '/user-view-query/remarks/edit/:id', name: 'User View Query Remarks Edit', element: EditRemarks },
  { path: '/code', name: 'User Code List', element: SignUpCodeList },
  { path: '/code/create', name: 'User Code Create', element: CreateSignUpCode },
  { path: '/members-summary', name: 'Members Summary List', element: SummaryList },
  { path: '/subscription-summary/create', name: 'Subscription Summary Create', element: CreatePaymentLink },
  { path: '/payment-received', name: 'Payment Received List', element: PaymentRecievedList },
  { path: '/payment-refunded', name: 'Payment Refunded List', element: PaymentRefundedList },
  { path: '/transaction', name: 'Transaction List', element: TransactionList },

  { path: '/product', name: 'Product List', element: ProductList },
  { path: '/product/create', name: 'Product Create', element: CreateProduct },
  { path: '/product/edit/:id', name: 'Product Edit', element: UpdateProduct },

  { path: '/subcription-plan', name: 'Subcription Plan List', element: SubcriptionPlanList },
  { path: '/subcription-plan/create', name: 'Subcription Plan Create', element: SubscriptionPlanCreate },
  { path: '/subcription-plan/edit/:id', name: 'Subcription Plan Edit', element: SubcriptionPlanUpdate },

  { path: '/member-details/:id', name: 'User Details', element: UserDetails },


  { path: '/logout', name: 'Logout', element: Logout },

]

export default routes
